def login_redirect(user_authenticated, destination_id):
    # Allowlist of valid destination route identifiers
    valid_destinations = {
        'home': '/home',
        'dashboard': '/dashboard',
        'profile': '/profile',
        'settings': '/settings'
    }
    
    if user_authenticated:
        # Validate the destination_id against the allowlist
        if destination_id in valid_destinations:
            return valid_destinations[destination_id]
        else:
            # Default to a safe page if the destination is not valid
            return '/home'
    else:
        # Redirect to login page if user is not authenticated
        return '/login'

